// Process raw data into word objects
const wordsOrdered = raw.map(([img, en, zh, category, level, sentence, sentenceZh]) => ({
  id: img.replace(/\.jpg$/i, '').toLowerCase().replace(/[\s']+/g, '-').replace(/[^a-z0-9-]/g, ''),
  en, zh, category, level, sentence, sentenceZh, img,
}));

// Seeded shuffle so order is stable per session but randomized across sessions
function shuffleArray(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

export const wordsShuffled = shuffleArray(wordsOrdered);
export const words = wordsOrdered;
export const categories = ['all', ...Object.keys(categoryLabels).filter(k => k !== 'all')];
